/**
 * Integration Tests for Classification Pipeline
 *
 * These tests validate end-to-end pipeline behavior with real stages,
 * including domain lookup integration and complete classification flows.
 */

import { ClassificationPipeline } from '../../src/pipeline/classification-pipeline';
import { EmailMessage } from '../../src/types/email-message';
import { CategoryConfiguration, ProcessingConfig } from '../../src/types/category-configuration';

describe('ClassificationPipeline Integration Tests', () => {
  // Mock email for testing
  const mockEmail: EmailMessage = {
    id: 'test-msg-001',
    threadId: 'thread-001',
    gmailLabels: ['INBOX'],
    payload: {
      mimeType: 'text/plain',
      headers: [
        { name: 'Subject', value: 'Test Email' },
        { name: 'From', value: 'sender@example.com' },
        { name: 'To', value: 'recipient@example.com' },
        { name: 'Date', value: new Date().toISOString() },
      ],
      body: {
        data: Buffer.from('Test email body content').toString('base64url'),
      },
    },
    subject: 'Test Email',
    from: { email: 'sender@example.com', name: 'Sender', raw: 'Sender <sender@example.com>' },
    to: [{ email: 'recipient@example.com', name: 'Recipient', raw: 'Recipient <recipient@example.com>' }],
    date: new Date(),
    bodyPlain: 'Test email body content',
    isProcessed: false,
    processingPriority: 1,
  };

  // Minimal config for integration tests
  const minimalProcessingConfig: ProcessingConfig = {
    version: 1,
    taxonomyNotes: 'Integration test configuration',
    settings: {
      initialization: {
        applyHardAssertions: true,
        seedCategoryScores: true,
      },
      ruleScoring: {
        useLexicalPatterns: true,
        applySubtypeRules: true,
        boundedAggregation: true,
      },
      attributeProcessing: {
        detectSelfSent: true,
        resolveDomains: true,
        deriveContextFlags: true,
      },
      attributeInfluence: {
        applyBonuses: true,
        applyPenalties: true,
        enforceCaps: true,
      },
      disambiguation: {
        pairwiseAdjustments: true,
        confidenceGapThreshold: 0.15,
      },
      multiLabelSelection: {
        maxLabels: 2,
        minSecondaryConfidence: 0.6,
        allowedCombinations: [],
      },
      aiRouting: {
        highConfidenceThreshold: 0.01, // Skip AI for any classification
        aiRequiredThreshold: 0.99, // Don't trigger AI
        skipAiConditions: [],
      },
    },
    confidenceThresholds: {
      highConfidence: 0.8,
      mediumConfidence: 0.5,
      lowConfidence: 0.3,
      aiClassificationRequired: 0.6,
      manualReviewRequired: 0.2,
      secondaryLabelMinGap: 0.15,
    },
    categorySignals: {},
    multiLabelPolicy: {
      maxTopLevelLabels: 2,
      minConfidenceForAdditional: 0.6,
      minDeltaPrimarySecondary: 0.15,
      allowFinancialActionableCopresence: false,
    },
    domainSignalOverrides: {},
    domainSignalResolution: {
      mode: 'runtimeResolved',
      source: 'config/domain-sources.json',
      notes: 'Test configuration',
    },
    topLevelCategories: {},
    attributes: {
      schema: {},
      detectors: [],
      derived: {},
      attributeBonusMap: {},
    },
    attributeRelevance: {
      RolesLegend: {
        CORE: 'Core attribute',
        PRIMARY_BOOST: 'Primary boost',
        SECONDARY_BOOST: 'Secondary boost',
        DISAMBIGUATOR: 'Disambiguator',
        FILTER: 'Filter',
        STRUCTURAL: 'Structural',
        DERIVED_LINK: 'Derived link',
        NEUTRAL: 'Neutral',
      },
    },
    aiPrompts: {
      featureExtraction: {
        systemPrompt: [],
        userPrompt: [],
      },
      finalClassification: {
        systemPrompt: [],
        userPrompt: [],
      },
    },
    featureExtractionSchema: {
      type: 'object',
      properties: {},
      required: [],
      additionalProperties: false,
    },
  };

  const minimalConfig: CategoryConfiguration = {
    version: '1.0.0',
    lastModified: new Date(),
    hash: 'test-config-hash',
    processingConfig: minimalProcessingConfig,
    schemaVersion: '1.0',
    validationPassed: true,
    validationErrors: [],
    compiledRules: [],
    attributeMatrix: {},
  };

  describe('Domain Lookup Integration (T038a)', () => {
    it('should load domain lookup from config/domain-sources.json on initialization', () => {
      const pipeline = new ClassificationPipeline(minimalConfig);

      // Pipeline should initialize successfully with loaded domains
      expect(pipeline).toBeDefined();
    });

    it.skip('should use loaded domains for hard assertions with financial category', async () => {
      const pipeline = new ClassificationPipeline(minimalConfig);

      // Create email from a known financial domain (chase.com from domain-sources.json)
      const financialEmail: EmailMessage = {
        ...mockEmail,
        id: 'financial-test-001',
        subject: 'Your Chase account statement',
        from: { email: 'alerts@chase.com', name: 'Chase', raw: 'Chase <alerts@chase.com>' },
        bodyPlain: 'Your account statement is ready.',
      };

      const result = await pipeline.classify(financialEmail);

      // Should classify with financial category due to domain lookup
      expect(result).toBeDefined();
      expect(result.primaryCategory).toBeDefined();

      // If hard assertions triggered, should see high confidence
      if (result.primaryCategory === 'financial') {
        expect(result.confidence).toBeGreaterThanOrEqual(0.7);
      }
    });

    it.skip('should use loaded domains for strong indicators with newsletter category', async () => {
      const pipeline = new ClassificationPipeline(minimalConfig);

      // Create email from a known newsletter domain (medium.com from domain-sources.json)
      const newsletterEmail: EmailMessage = {
        ...mockEmail,
        id: 'newsletter-test-001',
        subject: 'New stories from Medium',
        from: { email: 'noreply@medium.com', name: 'Medium', raw: 'Medium <noreply@medium.com>' },
        bodyPlain: 'Check out these new stories...',
      };

      const result = await pipeline.classify(newsletterEmail);

      // Should classify with newsletter category due to domain lookup
      expect(result).toBeDefined();
      expect(result.primaryCategory).toBeDefined();

      // Domain lookup should contribute to scoring
      if (result.primaryCategory === 'newsletter') {
        expect(result.confidence).toBeGreaterThanOrEqual(0.5);
      }
    });

    it('should handle missing domain-sources.json gracefully', () => {
      // Pipeline initialization should not throw even if domain-sources.json is missing
      // (loadDomainLookup returns empty lookup with warning)
      expect(() => new ClassificationPipeline(minimalConfig)).not.toThrow();
    });
  });
});

