    version: '1.0.0',
    lastModified: new Date(),
    hash: 'test-config-hash',
    processingConfig: minimalProcessingConfig,
    schemaVersion: '1.0',
    validationPassed: true,
    validationErrors: [],
    compiledRules: [],
    attributeMatrix: {},
  };

  describe('Domain Lookup Integration (T038a)', () => {
    it('should load domain lookup from config/domain-sources.json on initialization', () => {
      const pipeline = new ClassificationPipeline(minimalConfig);

      // Pipeline should initialize successfully with loaded domains
      expect(pipeline).toBeDefined();
    });

    it.skip('should use loaded domains for hard assertions with financial category', async () => {
      const pipeline = new ClassificationPipeline(minimalConfig);

      // Create email from a known financial domain (chase.com from domain-sources.json)
      const financialEmail: EmailMessage = {
        ...mockEmail,
        id: 'financial-test-001',
        subject: 'Your Chase account statement',
        from: { email: 'alerts@chase.com', name: 'Chase', raw: 'Chase <alerts@chase.com>' },
        bodyPlain: 'Your account statement is ready.',
      };

      const result = await pipeline.classify(financialEmail);

      // Should classify with financial category due to domain lookup
      expect(result).toBeDefined();
      expect(result.primaryCategory).toBeDefined();

      // If hard assertions triggered, should see high confidence
      if (result.primaryCategory === 'financial') {
        expect(result.confidence).toBeGreaterThanOrEqual(0.7);
      }
    });

    it.skip('should use loaded domains for strong indicators with newsletter category', async () => {
      const pipeline = new ClassificationPipeline(minimalConfig);

      // Create email from a known newsletter domain (medium.com from domain-sources.json)
      const newsletterEmail: EmailMessage = {
        ...mockEmail,
        id: 'newsletter-test-001',
        subject: 'New stories from Medium',
        from: { email: 'noreply@medium.com', name: 'Medium', raw: 'Medium <noreply@medium.com>' },
        bodyPlain: 'Check out these new stories...',
      };

      const result = await pipeline.classify(newsletterEmail);

      // Should classify with newsletter category due to domain lookup
      expect(result).toBeDefined();
      expect(result.primaryCategory).toBeDefined();

      // Domain lookup should contribute to scoring
      if (result.primaryCategory === 'newsletter') {
        expect(result.confidence).toBeGreaterThanOrEqual(0.5);
      }
    });

    it('should handle missing domain-sources.json gracefully', () => {
      // Pipeline initialization should not throw even if domain-sources.json is missing
      // (loadDomainLookup returns empty lookup with warning)
      expect(() => new ClassificationPipeline(minimalConfig)).not.toThrow();
    });
  });
});

