      source: 'config/domain-sources.json',
      notes: 'Test configuration',
    },
    topLevelCategories: {
      financial: {
        description: 'Financial and banking emails',
        subtypes: {},
      },
      newsletter: {
        description: 'Newsletter and digest emails',
        subtypes: {},
      },
    },
    attributes: {
      schema: {},
      detectors: [],
      derived: {},
      attributeBonusMap: {},
    },
    attributeRelevance: {
      RolesLegend: {
        CORE: 'Core attribute',
        PRIMARY_BOOST: 'Primary boost',
        SECONDARY_BOOST: 'Secondary boost',
        DISAMBIGUATOR: 'Disambiguator',
        FILTER: 'Filter',
        STRUCTURAL: 'Structural',
        DERIVED_LINK: 'Derived link',
