    33→  createClassificationSession,
    34→  createClassificationResult,
    35→  incrementSessionSuccess,
    36→  incrementSessionError,
    37→  finalizeClassificationSession,
    38→} from '../utils/initialization';
    39→
    40→// Pipeline stages (canonical signatures)
    41→import { executeHardAssertions } from '../stages/hard-assertions';
    42→import { executeStrongIndicators } from '../stages/strong-indicators';
    43→import { executeRuleScoring } from '../stages/rule-scoring';
    44→import { executeAttributeDetection } from '../stages/attribute-detection';
    45→import { executeAttributeInfluence } from '../stages/attribute-influence';
    46→import { executeDisambiguation } from '../stages/disambiguation';
    47→import { executeMultiLabelSelection } from '../stages/multi-label-selection';
    48→import { aiRoutingStage } from '../stages/ai-routing';
